INSERT OR REPLACE INTO hot_topics (id, title, summary, content, source, source_url, author, categories, tags, keywords, hot_value, view_count, like_count, comment_count, quality_score, relevance_score, published_at, fetched_at, hot_comments, guide_questions) VALUES (136, 'The Latent Color Subspace: Emergent Order in High-Dimensional Chaos', 'Text-to-image generation models have advanced rapidly, yet achieving fine-grained control over generated images remains difficult, largely due to limited understanding of how semantic information is encoded. We develop an interpretation of the color representation in the Variational Autoencoder latent space of FLUX.1 [Dev], revealing a structure reflecting Hue, Saturation, and Lightness. We verify our Latent Color Subspace (LCS) interpretation by demonstrating that it can both predict and explic', NULL, 'arXiv Machine Learning', 'https://arxiv.org/abs/2603.12261v1', NULL, '["academic"]', '["\u673a\u5668\u5b66\u4e60", "cs.AI", "cs.LG", "\u8bba\u6587", "\u5b66\u672f", "cs.CV"]', '[]', 0, 0, 0, 0, 0.95, 0.0, '2026-03-12 17:59:48.000000', '2026-04-03 00:49:46', '[]', '[]');
INSERT OR REPLACE INTO hot_topics (id, title, summary, content, source, source_url, author, categories, tags, keywords, hot_value, view_count, like_count, comment_count, quality_score, relevance_score, published_at, fetched_at, hot_comments, guide_questions) VALUES (137, 'NeuralOS: Towards Simulating Operating Systems via Neural Generative Models', 'We introduce NeuralOS, a neural framework that simulates graphical user interfaces (GUIs) of operating systems by directly predicting screen frames in response to user inputs such as mouse movements, clicks, and keyboard events. NeuralOS combines a recurrent neural network (RNN), which tracks computer state, with a diffusion-based neural renderer that generates screen images. The model is trained on a dataset of Ubuntu XFCE recordings, which include both randomly generated interactions and reali', NULL, 'arXiv NLP', 'https://arxiv.org/abs/2507.08800v2', NULL, '["academic"]', '["cs.AI", "cs.LG", "cs.HC", "\u8bba\u6587", "cs.CL", "\u5b66\u672f", "NLP", "cs.CV"]', '[]', 0, 0, 0, 0, 0.95, 0.0, '2025-07-11 17:59:40.000000', '2026-04-03 00:49:46', '[]', '[]');
INSERT OR REPLACE INTO hot_topics (id, title, summary, content, source, source_url, author, categories, tags, keywords, hot_value, view_count, like_count, comment_count, quality_score, relevance_score, published_at, fetched_at, hot_comments, guide_questions) VALUES (138, 'SciMDR: Benchmarking and Advancing Scientific Multimodal Document Reasoning', 'Constructing scientific multimodal document reasoning datasets for foundation model training involves an inherent trade-off among scale, faithfulness, and realism. To address this challenge, we introduce the synthesize-and-reground framework, a two-stage pipeline comprising: (1) Claim-Centric QA Synthesis, which generates faithful, isolated QA pairs and reasoning on focused segments, and (2) Document-Scale Regrounding, which programmatically re-embeds these pairs into full-document tasks to ensu', NULL, 'arXiv NLP', 'https://arxiv.org/abs/2603.12249v1', NULL, '["academic"]', '["cs.AI", "\u8bba\u6587", "cs.CL", "\u5b66\u672f", "NLP", "cs.CV"]', '[]', 0, 0, 0, 0, 0.95, 0.0, '2026-03-12 17:57:52.000000', '2026-04-03 00:49:46', '[]', '[]');
INSERT OR REPLACE INTO hot_topics (id, title, summary, content, source, source_url, author, categories, tags, keywords, hot_value, view_count, like_count, comment_count, quality_score, relevance_score, published_at, fetched_at, hot_comments, guide_questions) VALUES (139, 'Examining Reasoning LLMs-as-Judges in Non-Verifiable LLM Post-Training', 'Reasoning LLMs-as-Judges, which can benefit from inference-time scaling, provide a promising path for extending the success of reasoning models to non-verifiable domains where the output correctness/quality cannot be directly checked. However, while reasoning judges have shown better performance on static evaluation benchmarks, their effectiveness in actual policy training has not been systematically examined. Therefore, we conduct a rigorous study to investigate the actual impact of non-reasoni', NULL, 'arXiv NLP', 'https://arxiv.org/abs/2603.12246v1', NULL, '["academic"]', '["cs.AI", "cs.LG", "\u8bba\u6587", "cs.CL", "\u5b66\u672f", "NLP"]', '[]', 0, 0, 0, 0, 0.95, 0.0, '2026-03-12 17:57:06.000000', '2026-04-03 00:49:46', '[]', '[]');
INSERT OR REPLACE INTO hot_topics (id, title, summary, content, source, source_url, author, categories, tags, keywords, hot_value, view_count, like_count, comment_count, quality_score, relevance_score, published_at, fetched_at, hot_comments, guide_questions) VALUES (140, 'Separable neural architectures as a primitive for unified predictive and generative intelligence', 'Intelligent systems across physics, language and perception often exhibit factorisable structure, yet are typically modelled by monolithic neural architectures that do not explicitly exploit this structure. The separable neural architecture (SNA) addresses this by formalising a representational class that unifies additive, quadratic and tensor-decomposed neural models. By constraining interaction order and tensor rank, SNAs impose a structural inductive bias that factorises high-dimensional mapp', NULL, 'arXiv Machine Learning', 'https://arxiv.org/abs/2603.12244v1', NULL, '["academic"]', '["\u673a\u5668\u5b66\u4e60", "cs.AI", "cs.LG", "\u8bba\u6587", "\u5b66\u672f"]', '[]', 0, 0, 0, 0, 0.95, 0.0, '2026-03-12 17:56:54.000000', '2026-04-03 00:49:46', '[]', '[]');
INSERT OR REPLACE INTO hot_topics (id, title, summary, content, source, source_url, author, categories, tags, keywords, hot_value, view_count, like_count, comment_count, quality_score, relevance_score, published_at, fetched_at, hot_comments, guide_questions) VALUES (141, 'Incremental Neural Network Verification via Learned Conflicts', 'Neural network verification is often used as a core component within larger analysis procedures, which generate sequences of closely related verification queries over the same network. In existing neural network verifiers, each query is typically solved independently, and information learned during previous runs is discarded, leading to repeated exploration of the same infeasible regions of the search space. In this work, we aim to expedite verification by reducing this redundancy. We propose an', NULL, 'arXiv AI', 'https://arxiv.org/abs/2603.12232v1', NULL, '["academic"]', '["cs.AI", "AI", "\u8bba\u6587", "\u5b66\u672f", "cs.LO"]', '[]', 0, 0, 0, 0, 0.95, 0.0, '2026-03-12 17:52:12.000000', '2026-04-03 00:49:46', '[]', '[]');
INSERT OR REPLACE INTO hot_topics (id, title, summary, content, source, source_url, author, categories, tags, keywords, hot_value, view_count, like_count, comment_count, quality_score, relevance_score, published_at, fetched_at, hot_comments, guide_questions) VALUES (142, 'Security Considerations for Artificial Intelligence Agents', 'This article, a lightly adapted version of Perplexity''s response to NIST/CAISI Request for Information 2025-0035, details our observations and recommendations concerning the security of frontier AI agents. These insights are informed by Perplexity''s experience operating general-purpose agentic systems used by millions of users and thousands of enterprises in both controlled and open-world environments. Agent architectures change core assumptions around code-data separation, authority boundaries,', NULL, 'arXiv Machine Learning', 'https://arxiv.org/abs/2603.12230v1', NULL, '["academic"]', '["\u673a\u5668\u5b66\u4e60", "cs.AI", "cs.LG", "cs.CR", "\u8bba\u6587", "\u5b66\u672f"]', '[]', 0, 0, 0, 0, 0.95, 0.0, '2026-03-12 17:49:39.000000', '2026-04-03 00:49:46', '[]', '[]');
INSERT OR REPLACE INTO hot_topics (id, title, summary, content, source, source_url, author, categories, tags, keywords, hot_value, view_count, like_count, comment_count, quality_score, relevance_score, published_at, fetched_at, hot_comments, guide_questions) VALUES (143, 'Neural Thickets: Diverse Task Experts Are Dense Around Pretrained Weights', 'Pretraining produces a learned parameter vector that is typically treated as a starting point for further iterative adaptation. In this work, we instead view the outcome of pretraining as a distribution over parameter vectors, whose support already contains task-specific experts. We show that in small models such expert solutions occupy a negligible fraction of the volume of this distribution, making their discovery reliant on structured optimization methods such as gradient descent. In contrast', NULL, 'arXiv Machine Learning', 'https://arxiv.org/abs/2603.12228v1', NULL, '["academic"]', '["\u673a\u5668\u5b66\u4e60", "cs.AI", "cs.LG", "\u8bba\u6587", "\u5b66\u672f"]', '[]', 0, 0, 0, 0, 0.95, 0.0, '2026-03-12 17:49:30.000000', '2026-04-03 00:49:46', '[]', '[]');
INSERT OR REPLACE INTO hot_topics (id, title, summary, content, source, source_url, author, categories, tags, keywords, hot_value, view_count, like_count, comment_count, quality_score, relevance_score, published_at, fetched_at, hot_comments, guide_questions) VALUES (144, 'Sparking Scientific Creativity via LLM-Driven Interdisciplinary Inspiration', 'Despite interdisciplinary research leading to larger and longer-term impact, most work remains confined to single-domain academic silos. Recent AI-based approaches to scientific discovery show promise for interdisciplinary research, but many prioritize rapidly designing experiments and solutions, bypassing the exploratory, collaborative reasoning processes that drive creative interdisciplinary breakthroughs. As a result, prior efforts largely prioritize automating scientific discovery rather tha', NULL, 'arXiv NLP', 'https://arxiv.org/abs/2603.12226v1', NULL, '["academic"]', '["cs.AI", "\u8bba\u6587", "cs.CL", "\u5b66\u672f", "NLP"]', '[]', 0, 0, 0, 0, 0.95, 0.0, '2026-03-12 17:48:34.000000', '2026-04-03 00:49:46', '[]', '[]');
INSERT OR REPLACE INTO hot_topics (id, title, summary, content, source, source_url, author, categories, tags, keywords, hot_value, view_count, like_count, comment_count, quality_score, relevance_score, published_at, fetched_at, hot_comments, guide_questions) VALUES (145, 'Portfolio of Solving Strategies in CEGAR-based Object Packing and Scheduling for Sequential 3D Printing', 'Computing power that used to be available only in supercomputers decades ago especially their parallelism is currently available in standard personal computer CPUs even in CPUs for mobile telephones. We show how to effectively utilize the computing power of modern multi-core personal computer CPU to solve the complex combinatorial problem of object arrangement and scheduling for sequential 3D printing. We achieved this by parallelizing the existing CEGAR-SEQ algorithm that solves the sequential ', NULL, 'arXiv AI', 'https://arxiv.org/abs/2603.12224v1', NULL, '["academic"]', '["\u8bba\u6587", "AI", "cs.AI", "\u5b66\u672f"]', '[]', 0, 0, 0, 0, 0.95, 0.0, '2026-03-12 17:48:14.000000', '2026-04-03 00:49:46', '[]', '[]');
INSERT OR REPLACE INTO hot_topics (id, title, summary, content, source, source_url, author, categories, tags, keywords, hot_value, view_count, like_count, comment_count, quality_score, relevance_score, published_at, fetched_at, hot_comments, guide_questions) VALUES (146, 'HOG-Diff: Higher-Order Guided Diffusion for Graph Generation', 'Graph generation is a critical yet challenging task, as empirical analyses require a deep understanding of complex, non-Euclidean structures. Diffusion models have recently made significant advances in graph generation, but these models are typically adapted from image generation frameworks and overlook inherent higher-order topology, limiting their ability to capture graph topology. In this work, we propose Higher-order Guided Diffusion (HOG-Diff), a principled framework that progressively gene', NULL, 'arXiv Machine Learning', 'https://arxiv.org/abs/2502.04308v3', NULL, '["academic"]', '["\u673a\u5668\u5b66\u4e60", "cs.AI", "cs.LG", "cs.SI", "\u8bba\u6587", "\u5b66\u672f", "physics.soc-ph"]', '[]', 0, 0, 0, 0, 0.95, 0.0, '2025-02-06 18:51:14.000000', '2026-04-03 00:49:46', '[]', '[]');
INSERT OR REPLACE INTO hot_topics (id, title, summary, content, source, source_url, author, categories, tags, keywords, hot_value, view_count, like_count, comment_count, quality_score, relevance_score, published_at, fetched_at, hot_comments, guide_questions) VALUES (147, 'RDNet: Region Proportion-Aware Dynamic Adaptive Salient Object Detection Network in Optical Remote Sensing Images', 'Salient object detection (SOD) in remote sensing images faces significant challenges due to large variations in object sizes, the computational cost of self-attention mechanisms, and the limitations of CNN-based extractors in capturing global context and long-range dependencies. Existing methods that rely on fixed convolution kernels often struggle to adapt to diverse object scales, leading to detail loss or irrelevant feature aggregation. To address these issues, this work aims to enhance robus', NULL, 'arXiv AI', 'https://arxiv.org/abs/2603.12215v1', NULL, '["academic"]', '["cs.AI", "AI", "\u8bba\u6587", "\u5b66\u672f", "cs.CV"]', '[]', 0, 0, 0, 0, 0.95, 0.0, '2026-03-12 17:34:29.000000', '2026-04-03 00:49:46', '[]', '[]');
INSERT OR REPLACE INTO hot_topics (id, title, summary, content, source, source_url, author, categories, tags, keywords, hot_value, view_count, like_count, comment_count, quality_score, relevance_score, published_at, fetched_at, hot_comments, guide_questions) VALUES (148, 'WORKSWORLD: A Domain for Integrated Numeric Planning and Scheduling of Distributed Pipelined Workflows', 'This work pursues automated planning and scheduling of distributed data pipelines, or workflows. We develop a general workflow and resource graph representation that includes both data processing and sharing components with corresponding network interfaces for scheduling. Leveraging these graphs, we introduce WORKSWORLD, a new domain for numeric domain-independent planners designed for permanently scheduled workflows, like ingest pipelines. Our framework permits users to define data sources, ava', NULL, 'arXiv AI', 'https://arxiv.org/abs/2603.12214v1', NULL, '["academic"]', '["cs.AI", "AI", "cs.DC", "\u8bba\u6587", "\u5b66\u672f"]', '[]', 0, 0, 0, 0, 0.95, 0.0, '2026-03-12 17:34:04.000000', '2026-04-03 00:49:46', '[]', '[]');
INSERT OR REPLACE INTO hot_topics (id, title, summary, content, source, source_url, author, categories, tags, keywords, hot_value, view_count, like_count, comment_count, quality_score, relevance_score, published_at, fetched_at, hot_comments, guide_questions) VALUES (149, 'LLMTrack: Semantic Multi-Object Tracking with Multi-modal Large Language Models', 'Multi-Object Tracking (MOT) is evolving from geometric localization to Semantic MOT (SMOT) to answer complex relational queries, yet progress is hindered by semantic data scarcity and a structural disconnect between tracking architectures and Multi-modal Large Language Models (MLLMs). To address this, we introduce Grand-SMOT, a large-scale, open-world benchmark providing high-density, dual-stream narratives that comprehensively decouple individual behaviors from environmental contexts. Furthermo', NULL, 'arXiv AI', 'https://arxiv.org/abs/2601.06550v2', NULL, '["academic"]', '["cs.AI", "AI", "\u8bba\u6587", "\u5b66\u672f", "cs.CV"]', '[]', 0, 0, 0, 0, 0.95, 0.0, '2026-01-10 12:18:12.000000', '2026-04-03 00:49:46', '[]', '[]');
INSERT OR REPLACE INTO hot_topics (id, title, summary, content, source, source_url, author, categories, tags, keywords, hot_value, view_count, like_count, comment_count, quality_score, relevance_score, published_at, fetched_at, hot_comments, guide_questions) VALUES (150, 'Compiling Temporal Numeric Planning into Discrete PDDL+: Extended Version', 'Since the introduction of the PDDL+ modeling language, it was known that temporal planning with durative actions (as in PDDL 2.1) could be compiled into PDDL+. However, no practical compilation was presented in the literature ever since. We present a practical compilation from temporal planning with durative actions into PDDL+, fully capturing the semantics and only assuming the non-self-overlapping of actions. Our compilation is polynomial, retains the plan length up to a constant factor and is', NULL, 'arXiv AI', 'https://arxiv.org/abs/2603.12188v1', NULL, '["academic"]', '["\u8bba\u6587", "AI", "cs.AI", "\u5b66\u672f"]', '[]', 0, 0, 0, 0, 0.95, 0.0, '2026-03-12 17:19:30.000000', '2026-04-03 00:49:46', '[]', '[]');
INSERT OR REPLACE INTO hot_topics (id, title, summary, content, source, source_url, author, categories, tags, keywords, hot_value, view_count, like_count, comment_count, quality_score, relevance_score, published_at, fetched_at, hot_comments, guide_questions) VALUES (151, 'Proof-Carrying Materials: Falsifiable Safety Certificates for Machine-Learned Interatomic Potentials', 'Machine-learned interatomic potentials (MLIPs) are deployed for high-throughput materials screening without formal reliability guarantees. We show that a single MLIP used as a stability filter misses 93% of density functional theory (DFT)-stable materials (recall 0.07) on a 25,000-material benchmark. Proof-Carrying Materials (PCM) closes this gap through three stages: adversarial falsification across compositional space, bootstrap envelope refinement with 95% confidence intervals, and Lean 4 for', NULL, 'arXiv Machine Learning', 'https://arxiv.org/abs/2603.12183v1', NULL, '["academic"]', '["physics.comp-ph", "\u673a\u5668\u5b66\u4e60", "cs.AI", "cs.LG", "\u8bba\u6587", "cond-mat.mtrl-sci", "\u5b66\u672f"]', '[]', 0, 0, 0, 0, 0.95, 0.0, '2026-03-12 17:13:25.000000', '2026-04-03 00:49:46', '[]', '[]');
INSERT OR REPLACE INTO hot_topics (id, title, summary, content, source, source_url, author, categories, tags, keywords, hot_value, view_count, like_count, comment_count, quality_score, relevance_score, published_at, fetched_at, hot_comments, guide_questions) VALUES (152, 'Strategic Navigation or Stochastic Search? How Agents and Humans Reason Over Document Collections', 'Multimodal agents offer a promising path to automating complex document-intensive workflows. Yet, a critical question remains: do these agents demonstrate genuine strategic reasoning, or merely stochastic trial-and-error search? To address this, we introduce MADQA, a benchmark of 2,250 human-authored questions grounded in 800 heterogeneous PDF documents. Guided by Classical Test Theory, we design it to maximize discriminative power across varying levels of agentic abilities. To evaluate agentic ', NULL, 'arXiv NLP', 'https://arxiv.org/abs/2603.12180v1', NULL, '["academic"]', '["cs.AI", "\u8bba\u6587", "cs.CL", "\u5b66\u672f", "NLP"]', '[]', 0, 0, 0, 0, 0.95, 0.0, '2026-03-12 17:11:22.000000', '2026-04-03 00:49:46', '[]', '[]');
INSERT OR REPLACE INTO hot_topics (id, title, summary, content, source, source_url, author, categories, tags, keywords, hot_value, view_count, like_count, comment_count, quality_score, relevance_score, published_at, fetched_at, hot_comments, guide_questions) VALUES (153, 'BehaviorVLM: Unified Finetuning-Free Behavioral Understanding with Vision-Language Reasoning', 'Understanding freely moving animal behavior is central to neuroscience, where pose estimation and behavioral understanding form the foundation for linking neural activity to natural actions. Yet both tasks still depend heavily on human annotation or unstable unsupervised pipelines, limiting scalability and reproducibility. We present BehaviorVLM, a unified vision-language framework for pose estimation and behavioral understanding that requires no task-specific finetuning and minimal human labeli', NULL, 'arXiv AI', 'https://arxiv.org/abs/2603.12176v1', NULL, '["academic"]', '["cs.AI", "AI", "\u8bba\u6587", "\u5b66\u672f", "cs.CV"]', '[]', 0, 0, 0, 0, 0.95, 0.0, '2026-03-12 17:09:20.000000', '2026-04-03 00:49:46', '[]', '[]');
INSERT OR REPLACE INTO hot_topics (id, title, summary, content, source, source_url, author, categories, tags, keywords, hot_value, view_count, like_count, comment_count, quality_score, relevance_score, published_at, fetched_at, hot_comments, guide_questions) VALUES (154, 'Personalized Feature Translation for Expression Recognition: An Efficient Source-Free Domain Adaptation Method', 'Facial expression recognition (FER) models are widely used in video-based affective computing applications, such as human-computer interaction and healthcare monitoring. However, deep FER models often struggle with subtle expressions and high inter-subject variability, limiting performance in real-world settings. Source-free domain adaptation (SFDA) has been proposed to personalize a pretrained source model using only unlabeled target data, avoiding privacy, storage, and transmission constraints', NULL, 'arXiv AI', 'https://arxiv.org/abs/2508.09202v4', NULL, '["academic"]', '["cs.AI", "AI", "\u8bba\u6587", "\u5b66\u672f", "cs.CV"]', '[]', 0, 0, 0, 0, 0.95, 0.0, '2025-08-08 20:13:50.000000', '2026-04-03 00:49:46', '[]', '[]');
INSERT OR REPLACE INTO hot_topics (id, title, summary, content, source, source_url, author, categories, tags, keywords, hot_value, view_count, like_count, comment_count, quality_score, relevance_score, published_at, fetched_at, hot_comments, guide_questions) VALUES (155, 'A Quantitative Characterization of Forgetting in Post-Training', 'Continual post-training of generative models is widely used, yet a principled understanding of when and why forgetting occurs remains limited. We develop theoretical results under a two-mode mixture abstraction (representing old and new tasks), proposed by Chen et al. (2025) (arXiv:2510.18874), and formalize forgetting in two forms: (i) mass forgetting, where the old mixture weight collapses to zero, and (ii) old-component drift, where an already-correct old component shifts during training. For', NULL, 'arXiv Machine Learning', 'https://arxiv.org/abs/2603.12163v1', NULL, '["academic"]', '["\u673a\u5668\u5b66\u4e60", "cs.AI", "cs.LG", "math.ST", "stat.ML", "\u8bba\u6587", "\u5b66\u672f"]', '[]', 0, 0, 0, 0, 0.95, 0.0, '2026-03-12 17:00:16.000000', '2026-04-03 00:49:46', '[]', '[]');
